INSERT INTO `homepage_content` (`id`, `content_type`, `title`, `subtitle`, `description`, `badge_text`, `icon_class`, `image_path`, `content_order`, `is_active`, `external_link`, `link_text`, `meta_data`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES
(1, 'carousel_slide', 'What is African Swine Fever?', '', 'African Swine Fever (ASF) is a highly contagious viral disease of domestic and wild pigs with a mortality rate that can reach 100%. While it does not affect human health, ASF has devastating effects on pig populations and the farming economy. The virus is highly resistant in the environment and can survive on clothes, boots, wheels, and various pork products.', 'WOAH Listed Disease', '', 'uploads/contents/pigs_1.png', 1, 1, NULL, NULL, NULL, NULL, 1, '2026-01-11 01:13:29', '2026-01-11 01:22:03'),
(2, 'carousel_slide', 'Global Threat to Food Security', NULL, 'ASF continues to spread worldwide, affecting multiple countries across Asia, the Caribbean, Europe, and the Pacific. Pork meat accounts for more than 35% of global meat intake, making this disease a serious threat to food security. The spread of ASF has devastated family-run pig farms, impacting livelihoods and reducing opportunities for healthcare and education in affected communities.', 'Global Concern', NULL, 'uploads/contents/pigs_2.png', 2, 1, NULL, NULL, NULL, NULL, NULL, '2026-01-11 01:13:29', '2026-01-11 01:13:29'),
(3, 'carousel_slide', 'How ASF Spreads', NULL, 'ASF spreads through direct contact between infected pigs, ingestion of contaminated materials (food waste, feed, garbage), contact with contaminated fomites (clothing, footwear, vehicles), or bites from biological vectors (soft ticks). Human behaviors play an important role in spreading this disease across borders if adequate biosecurity measures are not implemented.', 'Disease Control', NULL, 'uploads/contents/pigs_3.png', 3, 1, NULL, NULL, NULL, NULL, NULL, '2026-01-11 01:13:29', '2026-01-11 01:13:29'),
(4, 'carousel_slide', 'Clinical Signs of ASF', NULL, 'Acute forms are characterized by high fever, depression, anorexia, hemorrhages in the skin (redness on ears, abdomen, and legs), abortion in pregnant sows, cyanosis, vomiting, diarrhea, and death within 6-13 days. Mortality rates may be as high as 100%. Subacute and chronic forms show less intense clinical signs but can still result in 30-70% mortality. Laboratory confirmation is essential to differentiate ASF from classical swine fever.', 'Early Detection', NULL, 'uploads/contents/pigs_4.png', 4, 1, NULL, NULL, NULL, NULL, NULL, '2026-01-11 01:13:29', '2026-01-11 01:13:29'),
(5, 'carousel_slide', 'Prevention & Control', NULL, 'Biosecurity is the most important and effective measure to prevent and control ASF. Rigorous implementation of biosecurity principles at farm level, increased vigilance at borders to prevent illegal movement of ASF-infected animals or commodities, and effective risk communication are essential. Despite its complexity, global control of ASF is possible with sustained effort and collaboration at national, regional, and international levels.', 'Biosecurity', NULL, 'uploads/contents/pigs_5.png', 5, 1, NULL, NULL, NULL, NULL, NULL, '2026-01-11 01:13:29', '2026-01-11 01:13:29'),
(6, 'page_header', 'ASF Surveillance Dashboard', 'Real-time monitoring and predictive analysis for African Swine Fever in CALABARZON', NULL, NULL, NULL, NULL, 1, 1, NULL, NULL, NULL, NULL, NULL, '2026-01-11 01:13:29', '2026-01-11 01:13:29'),
(7, 'feature_card', 'Predictive Modeling', NULL, 'Machine learning algorithms analyze historical data and environmental factors to forecast ASF trends and potential outbreaks.', NULL, 'bi-cpu-fill', NULL, 1, 1, NULL, NULL, NULL, NULL, NULL, '2026-01-11 01:13:29', '2026-01-11 01:13:29'),
(8, 'feature_card', 'Real-Time Monitoring', NULL, 'Continuous surveillance of environmental parameters, outbreak reports, and meat movement patterns for early detection.', NULL, 'bi-speedometer2', NULL, 2, 1, NULL, NULL, NULL, NULL, NULL, '2026-01-11 01:13:29', '2026-01-11 01:13:29'),
(9, 'feature_card', 'Data Management', NULL, 'Upload and manage environmental data, historical outbreaks, depopulation records, and meat movement logs efficiently.', NULL, 'bi-database-fill', NULL, 3, 1, NULL, NULL, NULL, NULL, NULL, '2026-01-11 01:13:29', '2026-01-11 01:13:29'),
(10, 'feature_card', 'GIS Visualization', NULL, 'Interactive maps with multiple layers showing outbreaks, risk zones, depopulation events, and movement routes.', NULL, 'bi-geo-fill', NULL, 4, 1, NULL, NULL, NULL, NULL, NULL, '2026-01-11 01:13:29', '2026-01-11 01:13:29'),
(11, 'feature_card', 'Alert & Notifications', NULL, 'Automated alerts for emerging outbreaks, high-risk zone identification, and critical surveillance updates via email.', NULL, 'bi-bell-fill', NULL, 5, 1, NULL, NULL, NULL, NULL, NULL, '2026-01-11 01:13:29', '2026-01-11 01:13:29'),
(12, 'feature_card', 'Reporting Tools', 'Report and Analytics', 'Generate comprehensive reports (PDF, CSV, Excel) summarizing outbreak trends, risk analysis, and predictive insights.', '', 'bi-file-earmark-text-fill', '', 6, 1, NULL, NULL, NULL, NULL, 1, '2026-01-11 01:13:29', '2026-01-11 01:18:26'),
(13, 'about_section', 'About ASF Surveillance System', NULL, 'The ASF Surveillance System for CALABARZON is a comprehensive GIS-based predictive monitoring platform designed to enhance early detection and effective management of African Swine Fever outbreaks. Developed in alignment with Bureau of Animal Industry (BAI), World Organisation for Animal Health (WOAH), and Food and Agriculture Organization (FAO) guidelines, this system integrates real-time data collection, machine learning algorithms, and interactive mapping to support proactive disease surveillance and outbreak response.', NULL, NULL, NULL, 1, 1, NULL, NULL, NULL, NULL, NULL, '2026-01-11 01:13:29', '2026-01-11 01:13:29');
