INSERT INTO `system_alerts` (`id`, `alert_code`, `alert_type`, `severity`, `title`, `message`, `related_resource_type`, `related_resource_id`, `location_province`, `location_city`, `latitude`, `longitude`, `status`, `acknowledged_by`, `acknowledged_at`, `resolved_by`, `resolved_at`, `email_sent`, `email_sent_at`, `created_by`, `created_at`, `updated_at`) VALUES
(17, 'ALERT20250101001', 'high_risk', 'critical', 'Critical: High-Risk Zone Detected in Cavite', 'A high-risk zone has been identified in Cavite Province. Immediate action required. Multiple outbreaks detected within 5km radius. Please implement enhanced surveillance and biosecurity measures.', 'risk_zone', NULL, 'Cavite', 'Imus', 14.42970000, 120.93710000, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-01 00:00:00', '2026-01-11 10:21:56'),
(18, 'ALERT20250102001', 'high_risk', 'high', 'High-Risk Zone Alert in Laguna', 'A high-risk zone has been identified in Laguna Province. Enhanced monitoring recommended. Recent outbreak detected in the area. Please ensure proper biosecurity protocols are in place.', 'risk_zone', NULL, 'Laguna', 'Calamba', 14.21160000, 121.16550000, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-02 01:15:00', '2026-01-11 10:21:56'),
(19, 'ALERT20250103001', 'outbreak', 'critical', 'New ASF Outbreak Confirmed in Batangas', 'A new ASF outbreak has been confirmed in Batangas Province. Immediate containment measures required. Affected animals: 150 heads. Please coordinate with local authorities for depopulation procedures.', 'outbreak', NULL, 'Batangas', 'Bauan', 13.79190000, 121.00530000, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-03 02:30:00', '2026-01-11 10:21:56'),
(20, 'ALERT20250104001', 'outbreak', 'high', 'Suspected ASF Outbreak in Rizal', 'A suspected ASF outbreak has been reported in Rizal Province. Laboratory confirmation pending. Initial reports indicate 50 affected animals. Please proceed with caution and enhanced monitoring.', 'outbreak', NULL, 'Rizal', 'Antipolo', 14.62550000, 121.12450000, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-04 03:45:00', '2026-01-11 10:21:56'),
(21, 'ALERT20250105001', 'depopulation', 'high', 'Depopulation Event Scheduled in Cavite', 'A depopulation event is scheduled for January 5, 2025 in Cavite Province. Approximately 200 animals will be depopulated. Please ensure all protocols are followed and compensation procedures are in place.', 'depopulation', NULL, 'Cavite', 'Bacoor', 14.45840000, 120.94250000, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-04 23:00:00', '2026-01-11 10:21:56'),
(22, 'ALERT20250106001', 'depopulation', 'medium', 'Depopulation Completed in Laguna', 'Depopulation event successfully completed in Laguna Province. Total animals depopulated: 120 heads. Compensation procedures are ongoing. Enhanced surveillance recommended for the surrounding areas.', 'depopulation', NULL, 'Laguna', 'San Pedro', 14.35950000, 121.04730000, 'resolved', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-06 06:20:00', '2026-01-11 10:21:56'),
(23, 'ALERT20250107001', 'meat_movement', 'high', 'Unauthorized Meat Movement Detected', 'Unauthorized meat movement has been detected between Cavite and Laguna provinces. Health certificate verification required. Please investigate and ensure compliance with movement restrictions.', 'meat_movement', NULL, 'Cavite', 'Dasmarinas', 14.32940000, 120.93670000, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-07 01:30:00', '2026-01-11 10:21:56'),
(24, 'ALERT20250108001', 'meat_movement', 'medium', 'High Volume Meat Movement in Quezon', 'High volume meat movement detected in Quezon Province. Verification of health certificates recommended. Please ensure all movement records are properly documented.', 'meat_movement', NULL, 'Quezon', 'Lucena', 13.93140000, 121.61740000, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-08 02:15:00', '2026-01-11 10:21:56'),
(25, 'ALERT20250109001', 'predictive', 'high', 'Predictive Model: High Outbreak Risk Forecast', 'Predictive model indicates high outbreak risk in selected areas of CALABARZON. Environmental factors and historical data suggest increased probability of ASF outbreaks in the next 7 days. Enhanced surveillance recommended.', 'predictive_model', NULL, 'CALABARZON', NULL, NULL, NULL, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-09 00:00:00', '2026-01-11 10:21:56'),
(26, 'ALERT20250110001', 'predictive', 'medium', 'Predictive Model: Moderate Risk Alert', 'Predictive model indicates moderate outbreak risk in certain areas. Environmental conditions and movement patterns suggest potential risk. Regular monitoring recommended.', 'predictive_model', NULL, 'CALABARZON', NULL, NULL, NULL, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-10 01:30:00', '2026-01-11 10:21:56'),
(27, 'ALERT20250111001', 'system', 'low', 'System Maintenance Scheduled', 'Scheduled system maintenance will occur on January 15, 2025 from 2:00 AM to 4:00 AM. The system may be temporarily unavailable during this time. Please save your work beforehand.', NULL, NULL, NULL, NULL, NULL, NULL, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-11 02:00:00', '2026-01-11 10:21:56'),
(28, 'ALERT20250112001', 'system', 'medium', 'Database Backup Completed', 'Daily database backup has been successfully completed. All system data has been backed up and secured. Backup location: secure server.', NULL, NULL, NULL, NULL, NULL, NULL, 'acknowledged', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-11 18:30:00', '2026-01-11 10:21:56'),
(29, 'ALERT20250113001', 'high_risk', 'critical', 'Critical: Multiple High-Risk Zones in Batangas', 'Multiple high-risk zones have been identified in Batangas Province. Immediate coordinated response required. Risk assessment indicates elevated threat level. Please activate emergency protocols.', 'risk_zone', NULL, 'Batangas', 'Lipa', 13.94110000, 121.16310000, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-13 00:45:00', '2026-01-11 10:21:56'),
(30, 'ALERT20250114001', 'high_risk', 'high', 'High-Risk Zone Alert in Quezon', 'A high-risk zone has been identified in Quezon Province. Recent activity detected. Enhanced monitoring and biosecurity measures recommended for surrounding areas.', 'risk_zone', NULL, 'Quezon', 'Tayabas', 14.02940000, 121.59250000, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-14 01:20:00', '2026-01-11 10:21:56'),
(31, 'ALERT20250115001', 'outbreak', 'critical', 'New Outbreak Confirmed in Cavite - Second Location', 'A second ASF outbreak has been confirmed in Cavite Province. This is in addition to the previous outbreak. Total affected animals across both locations: 300 heads. Coordinated response required.', 'outbreak', NULL, 'Cavite', 'Silang', 14.23060000, 120.97530000, 'active', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-15 03:00:00', '2026-01-11 10:21:56'),
(32, 'ALERT20250116001', 'outbreak', 'medium', 'Outbreak Contained in Rizal', 'Previous outbreak in Rizal Province has been successfully contained. No new cases reported in the past 7 days. Surveillance continues. Status changed to contained.', 'outbreak', NULL, 'Rizal', 'Antipolo', 14.62550000, 121.12450000, 'resolved', NULL, NULL, NULL, NULL, 0, NULL, 1, '2025-01-16 07:30:00', '2026-01-11 10:21:56');
